import{_ as t,o as a,c as s,ag as n}from"./chunks/framework.DFmy_ALI.js";const m=JSON.parse('{"title":"Presented Payments","description":"","frontmatter":{},"headers":[],"relativePath":"guide/presented-payments.md","filePath":"guide/presented-payments.md"}'),r={name:"guide/presented-payments.md"};function i(l,e,o,p,d,h){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="presented-payments" tabindex="-1">Presented Payments <a class="header-anchor" href="#presented-payments" aria-label="Permalink to &quot;Presented Payments&quot;">​</a></h1><p>Neptune. Astro follows the OpenWave presented-payments model for <strong>merchant-presented</strong> and <strong>customer-presented</strong> QR and NFC flows.</p><h2 id="the-short-version" tabindex="-1">The short version <a class="header-anchor" href="#the-short-version" aria-label="Permalink to &quot;The short version&quot;">​</a></h2><p>QR or NFC starts the flow. <strong>Astro still owns the secure authorization step</strong> and then reuses the normal payment or mandate lifecycle.</p><h2 id="what-astro-can-do-in-this-model" tabindex="-1">What Astro can do in this model <a class="header-anchor" href="#what-astro-can-do-in-this-model" aria-label="Permalink to &quot;What Astro can do in this model&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>What Astro does</th></tr></thead><tbody><tr><td>Merchant-presented QR</td><td>Creates presentment, returns QR payload, opens hosted checkout after claim</td></tr><tr><td>Merchant-presented NFC</td><td>Creates NDEF-compatible payload and resumes secure authorization after tap</td></tr><tr><td>Customer-presented token</td><td>Claims customer-presented QR or NFC token and converts it into a standard payment session</td></tr><tr><td>Presented mandate approval</td><td>Starts recurring-mandate approval from QR or NFC, then shows full consent scope before approval</td></tr></tbody></table><h2 id="what-astro-does-not-do" tabindex="-1">What Astro does not do <a class="header-anchor" href="#what-astro-does-not-do" aria-label="Permalink to &quot;What Astro does not do&quot;">​</a></h2><ul><li>It does not treat QR or NFC as final authorization.</li><li>It does not let merchants collect bank OTP or push-approval results directly.</li><li>It does not collapse payment consent and Open Banking consent into one unsafe shortcut.</li></ul><h2 id="merchant-presented-one-time-payment" tabindex="-1">Merchant-presented one-time payment <a class="header-anchor" href="#merchant-presented-one-time-payment" aria-label="Permalink to &quot;Merchant-presented one-time payment&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  autonumber</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant M as Merchant backend</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant UI as Merchant UI / POS</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant A as Neptune. Astro</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant C as Customer device</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  participant B as Bank</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  M-&gt;&gt;A: create presentment</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A--&gt;&gt;M: presentment_id + QR/NFC payload</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  M--&gt;&gt;UI: render QR or NFC target</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C-&gt;&gt;A: claim presentment</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A--&gt;&gt;C: hosted checkout / secure SDK surface</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C-&gt;&gt;B: OTP / push / SCA</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B--&gt;&gt;A: verified</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A--&gt;&gt;M: payment.completed webhook</span></span></code></pre></div><h2 id="presented-recurring-approval" tabindex="-1">Presented recurring approval <a class="header-anchor" href="#presented-recurring-approval" aria-label="Permalink to &quot;Presented recurring approval&quot;">​</a></h2><p>Use this when the customer starts a subscription from a QR or NFC handoff.</p><p>The customer must still see:</p><ul><li>merchant name</li><li>recurring amount or max amount</li><li>frequency</li><li>expiry or duration</li><li>cancellation rights</li></ul><p>Only after that can Astro collect bank OTP or push approval.</p><h2 id="security-rules" tabindex="-1">Security rules <a class="header-anchor" href="#security-rules" aria-label="Permalink to &quot;Security rules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rule</th><th>Why</th></tr></thead><tbody><tr><td>Presentments must expire</td><td>Prevent stale reuse</td></tr><tr><td>Claim must be replay-safe</td><td>Prevent duplicate or spoofed payment start</td></tr><tr><td>Hosted or SDK-controlled SCA is mandatory</td><td>Protect bank secrets</td></tr><tr><td>Merchant fulfilment waits for signed final state</td><td>Prevent early fulfilment on an incomplete flow</td></tr></tbody></table><h2 id="direct-bank-or-wallet-implementations" tabindex="-1">Direct bank or wallet implementations <a class="header-anchor" href="#direct-bank-or-wallet-implementations" aria-label="Permalink to &quot;Direct bank or wallet implementations&quot;">​</a></h2><p>OpenWave allows banks and wallets to implement the same presented-payment channel directly. Astro is one gateway implementation of that standard. If Astro interoperates with those direct implementations later, the capability discovery and claim lifecycle should remain identical.</p><h2 id="read-next" tabindex="-1">Read next <a class="header-anchor" href="#read-next" aria-label="Permalink to &quot;Read next&quot;">​</a></h2><ul><li><a href="./secure-flows.html">Secure Flows</a></li><li><a href="./subscriptions.html">Subscriptions</a></li><li><a href="./open-banking.html">Open Banking Consent</a></li><li><a href="https://neptune-ly.github.io/openwave-spec/guide/presented-payments.html" target="_blank" rel="noreferrer">OpenWave presented-payments standard</a></li></ul>`,21)])])}const u=t(r,[["render",i]]);export{m as __pageData,u as default};
